/*
 * Filament Tree — drag'n'drop bootstrap.
 * Filament v4 loads this script asynchronously via x-load-js (Async Alpine),
 * so it runs after `window load` has already fired. Boot off dependency
 * readiness instead of the `load` event.
 */

const initFilamentTree = () => {
    document.querySelectorAll("#studio15-tree .studio15-tree").forEach((list) => {
        Sortable.get(list)?.destroy();

        Sortable.create(list, {
            group: "tree-nested",
            animation: 150,
            fallbackOnBody: true,
            swapThreshold: 1,
            handle: ".handle",
            onEnd: (evt) => {
                const moved = {
                    id: evt.item.dataset.id,
                    ancestor: evt.from.dataset.id,
                    parent: evt.to.dataset.id,
                    from: evt.oldIndex,
                    to: evt.newIndex,
                };

                if (moved.parent === moved.ancestor && moved.from === moved.to) {
                    return;
                }

                Livewire.dispatch("filament-tree-moved", moved);
            },
        });
    });
};

const bootFilamentTree = () => {
    if (typeof Sortable === "undefined" || typeof Livewire === "undefined") {
        requestAnimationFrame(bootFilamentTree);
        return;
    }

    initFilamentTree();
    Livewire.hook("commit", ({ succeed }) => succeed(() => initFilamentTree()));
};

bootFilamentTree();
